// ========== ТЕМА ==========
const themeBtn=document.getElementById('theme-toggle'), themeClasses=['','light-theme','olive-theme'], themeIcons=['🌓','☀️','🌿']; let themeIdx=0;
function applyTheme(){ document.body.className=themeClasses[themeIdx]; themeBtn.textContent=themeIcons[themeIdx]; }
if(themeBtn) themeBtn.onclick=()=>{ themeIdx=(themeIdx+1)%themeClasses.length; applyTheme(); }; applyTheme();

// ========== ФОН ==========
const petalsContainer=document.getElementById('petals-container'); let flashesInitialized=false;
function initFlashes(){ if(flashesInitialized)return; petalsContainer.innerHTML=''; for(let i=0;i<12;i++){ const f=document.createElement('div'); f.className='flash'; f.style.left=(Math.random()*95)+'%'; f.style.top=(Math.random()*95)+'%'; f.style.animationDuration=(Math.random()*3+4)+'s'; f.style.animationDelay=(Math.random()*5)+'s'; petalsContainer.appendChild(f); } flashesInitialized=true; }

// ========== НАВИГАЦИЯ ==========
window.switchTab=(id)=>{ document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active')); document.querySelectorAll('.nav-btn').forEach(b=>b.classList.remove('active')); const target=document.getElementById(id); if(target)target.classList.add('active'); const navBtn=document.querySelector(`.nav-btn[data-tab="${id}"]`); if(navBtn)navBtn.classList.add('active'); const psych=document.getElementById('psychology'); if(id==='psychology'){ psych.classList.add('active'); createGeoFlowers(); petalsContainer.classList.remove('active'); } else { psych.classList.remove('active'); petalsContainer.classList.add('active'); if(!flashesInitialized)initFlashes(); } };
