const hList=document.getElementById('history-test-list');
if(hList){
  historyTests.forEach(t=>{ const card=document.createElement('div'); card.className='test-card'; card.innerHTML=`<h3>${t.title}</h3><span style="font-size:0.8rem;opacity:0.7">${t.questions.length} вопросов</span>`; card.onclick=()=>openHistoryFioModal(t); hList.appendChild(card); });
  console.log(`✅ Отрисовано тестов: ${historyTests.length}`);
} else { console.error('❌ Элемент #history-test-list не найден в HTML!'); }

function openHistoryFioModal(test){ pendingTestId='history'; historyUserInfo={test}; document.getElementById('fio-modal').style.display='flex'; document.getElementById('fio-input').value=''; document.getElementById('email-input').value=''; document.getElementById('fio-input').focus(); }
function startHistoryTest(){ if(!historyUserInfo)return; currentTest=historyUserInfo.test; qIdx=0; score=0; answered=false; webhookAnswers=[]; document.getElementById('fio-modal').style.display='none'; document.getElementById('history-test-list').classList.add('hidden'); document.getElementById('history-quiz').classList.remove('hidden'); document.getElementById('history-back-btn').classList.remove('hidden'); showHistoryQuestion(); }

function showHistoryQuestion(){ 
  const q=currentTest.questions[qIdx]; 
  document.getElementById('history-quiz').innerHTML=`<div class="question-frame" style="max-width:100%;overflow-wrap:break-word;"><h4>Вопрос ${qIdx+1} из ${currentTest.questions.length}</h4><p style="margin:15px 0;overflow-wrap:break-word;word-break:break-word;">${q.q}</p><div id="h-opts" style="display:flex;flex-direction:column;gap:10px;"></div></div>`; 
  const opts=document.getElementById('h-opts'); 
  
  if(!q.type || q.type==='single'){
    q.options.forEach((opt,i)=>{ 
      const btn=document.createElement('button'); btn.className='answer-option'; btn.textContent=opt;
      btn.style.cssText=`background:rgba(15,10,26,0.6);border:1px solid rgba(255,170,102,0.35);color:var(--text);padding:12px 16px;border-radius:12px;text-align:left;cursor:pointer;transition:0.2s;font-size:1rem;`;
      btn.onmouseenter=()=>{if(!answered){btn.style.borderColor='var(--accent)';btn.style.transform='translateX(4px)';}};
      btn.onmouseleave=()=>{if(!answered){btn.style.borderColor='rgba(255,170,102,0.35)';btn.style.transform='translateX(0)';}};
      btn.onclick=()=>checkHistoryAnswer({0:i}); opts.appendChild(btn); 
    });
  } 
  else if(q.type==='blanks'){
    let html=q.q;
    Object.keys(q.fields).forEach(n=>{
      const optsHtml=q.fields[n].map(v=>`<option value="${v}">${v}</option>`).join('');
      html=html.replace(`[[${n}]]`,`<select data-blank="${n}" style="margin:0 5px;padding:6px 10px;background:rgba(15,10,26,0.8);color:var(--text);border:1px solid var(--accent);border-radius:8px;cursor:pointer;"><option value="">-- выберите --</option>${optsHtml}</select>`);
    });
    document.querySelector('.question-frame p').innerHTML=html;
    const checkBtn=document.createElement('button'); checkBtn.textContent='✅ Проверить'; checkBtn.style.cssText='margin-top:15px;background:var(--accent);color:#0f0a1a;border:none;padding:10px 20px;border-radius:10px;cursor:pointer;font-weight:bold;align-self:center;';
    checkBtn.onclick=()=>{
      const sel={}; document.querySelectorAll('select[data-blank]').forEach(s=>sel[s.dataset.blank]=s.value);
      checkHistoryAnswer(sel); checkBtn.disabled=true; checkBtn.style.opacity='0.5';
    };
    opts.appendChild(checkBtn);
  }
  else if(q.type==='matching'){
    let html='<div style="display:flex;flex-direction:column;gap:10px;width:100%;">';
    const rightOpts=`<option value="">-- выберите --</option>`+q.right.map(v=>`<option value="${v}">${v}</option>`).join('');
    q.left.forEach((l,i)=>{
      html+=`<div style="display:flex;gap:10px;align-items:center;flex-wrap:wrap;"><span style="min-width:40%;color:var(--text);font-size:0.95rem;">${l}</span><select data-match="${i}" style="flex:1;min-width:150px;padding:6px 10px;background:rgba(15,10,26,0.8);color:var(--text);border:1px solid var(--accent);border-radius:8px;cursor:pointer;">${rightOpts}</select></div>`;
    });
    html+='</div>';
    document.querySelector('.question-frame p').innerHTML+=html;
    const checkBtn=document.createElement('button'); checkBtn.textContent='✅ Проверить'; checkBtn.style.cssText='margin-top:15px;background:var(--accent);color:#0f0a1a;border:none;padding:10px 20px;border-radius:10px;cursor:pointer;font-weight:bold;align-self:center;';
    checkBtn.onclick=()=>{
      const sel={}; document.querySelectorAll('select[data-match]').forEach(s=>sel[s.dataset.match]=s.value);
      checkHistoryAnswer(sel); checkBtn.disabled=true; checkBtn.style.opacity='0.5';
    };
    opts.appendChild(checkBtn);
  }
}

function checkHistoryAnswer(userSelection){ 
  if(answered)return; answered=true; 
  const q=currentTest.questions[qIdx]; 
  let isCorrect=false;
  
  if(q.type==='blanks'){
    isCorrect=Object.keys(q.correct).every(k=>userSelection[k]===q.correct[k]);
    document.querySelectorAll('select[data-blank]').forEach(s=>{
      const val=userSelection[s.dataset.blank];
      const corr=q.correct[s.dataset.blank];
      s.style.borderColor=val===corr?'#2ecc71':(val?'#e74c3c':'#ffb380');
      if(val===corr) s.style.boxShadow='0 0 0 2px rgba(46,204,113,0.25)';
      else if(val) s.style.boxShadow='0 0 0 2px rgba(231,76,60,0.25)';
    });
  } 
  else if(q.type==='matching'){
    isCorrect=Object.keys(q.correct).every(k=>userSelection[k]===q.correct[k]);
    document.querySelectorAll('select[data-match]').forEach(s=>{
      const idx=s.dataset.match;
      const val=userSelection[idx];
      const corr=q.correct[idx];
      s.style.borderColor=val===corr?'#2ecc71':(val?'#e74c3c':'#ffb380');
      if(val===corr) s.style.boxShadow='0 0 0 2px rgba(46,204,113,0.25)';
      else if(val) s.style.boxShadow='0 0 0 2px rgba(231,76,60,0.25)';
    });
  }
  else {
    isCorrect=userSelection[0]===q.correct;
    document.querySelectorAll('#h-opts .answer-option').forEach((el,i)=>{
      el.style.pointerEvents='none'; 
      if(i===q.correct){el.style.borderColor='#2ecc71';el.style.boxShadow='0 0 0 2px rgba(46,204,113,0.25)';} 
      else if(i===userSelection[0]){el.style.borderColor='#e74c3c';el.style.boxShadow='0 0 0 2px rgba(231,76,60,0.25)';} 
    });
  }
  
  // Показ исторической справки
  const frame=document.querySelector('.question-frame');
  if(q.note && !frame.querySelector('.history-note')){
    frame.insertAdjacentHTML('beforeend', `<div class="history-note" style="margin-top:15px;padding:12px;background:rgba(255,255,255,0.08);border-radius:10px;border-left:3px solid var(--accent);line-height:1.5;font-size:0.95rem;">📖 <b>Историческая справка:</b> ${q.note}</div>`);
  }

  if(isCorrect)score++;
  if(currentTest.id==='test_new_webhook'){
    const fmtAns=Object.values(userSelection).join(', ');
    webhookAnswers.push({num:qIdx+1,question:q.q,user_answer:fmtAns,correct_answer:q.type==='single'?q.options[q.correct]:Object.values(q.correct).join(', '),is_correct:isCorrect});
  }
  const nextBtn = document.createElement('button');
nextBtn.textContent = qIdx + 1 < currentTest.questions.length ? 'Далее →' : 'Показать результат 📊';
nextBtn.style.cssText = 'margin-top:15px;background:var(--accent);color:#0f0a1a;border:none;padding:12px 24px;border-radius:10px;cursor:pointer;font-weight:bold;align-self:center;';
nextBtn.onclick = () => {
  qIdx++;
  if(qIdx < currentTest.questions.length){
    answered = false;
    showHistoryQuestion();
  } else {
    finishHistoryTest();
  }
};
const opts = document.getElementById('h-opts');
if(opts) opts.appendChild(nextBtn); 
}

