function startPsychTest(id){currentTest=id==='kos'?{questions:kosQuestions,type:'kos'}:{questions:michelsonQuestions,type:'michelson'}; psychIndex=0;psychAnswers=[];michelsonScores={}; if(psychMenuView)psychMenuView.classList.add('hidden'); psychBackBtn.classList.add('hidden'); document.getElementById('psych-quiz').classList.remove('hidden');document.getElementById('psych-quiz').innerHTML=''; document.getElementById('psych-results').classList.add('hidden');document.getElementById('psych-results').innerHTML=''; showPsychQuestion(); }
function showPsychQuestion(){const q=currentTest.questions[psychIndex]; document.getElementById('psych-quiz').innerHTML=`<div class="progress-bar" style="max-width:100%;margin:0 auto 20px;"><div class="progress-fill" style="width:${(psychIndex/currentTest.questions.length)*100}%"></div></div><div class="question-box" style="max-width:95vw;padding:20px 15px;margin:0 auto 20px;overflow-wrap:break-word;"><p style="margin-bottom:20px;line-height:1.5;word-break:break-word;overflow-wrap:break-word;">${q.q}</p><div id="p-opts" style="display:flex;flex-direction:column;gap:10px;width:100%;"></div></div>`; const opts=document.getElementById('p-opts'); if(currentTest.type==='kos'){['Да','Нет'].forEach(a=>{const btn=document.createElement('button');btn.className='btn-answer';btn.textContent=a;btn.onclick=()=>answerPsych(a==='Да'?'yes':'no');opts.appendChild(btn);});} else {q.opts.forEach((opt,i)=>{const btn=document.createElement('button');btn.className='btn-answer';btn.textContent=`${String.fromCharCode(1072+i)}) ${opt}`;btn.onclick=()=>answerPsych(i);opts.appendChild(btn);});} const progress=(psychIndex+1)/currentTest.questions.length; if(progress>=0.32&&progress<0.35)document.getElementById('psych-quiz').insertAdjacentHTML('beforeend',`<div class="asya-message">🌸 Треть пройдена!</div>`); else if(progress>=0.64&&progress<0.67)document.getElementById('psych-quiz').insertAdjacentHTML('beforeend',`<div class="asya-message">✨ Две трети позади!</div>`); }
function answerPsych(ans){psychAnswers.push(ans);psychIndex++; if(psychIndex<currentTest.questions.length)showPsychQuestion(); else calculatePsychResults();}
function calculatePsychResults(){let html='',text=''; if(currentTest.type==='kos'){let c=0,o=0;psychAnswers.forEach((a,i)=>{const n=i+1;if(commYes.includes(n)&&a==='yes')c++;if(commNo.includes(n)&&a==='no')c++;if(orgYes.includes(n)&&a==='yes')o++;if(orgNo.includes(n)&&a==='no')o++;}); html=`<div class="result-item"><h4>🗣️ Коммуникативные</h4><p>Баллы: ${c}/20 | Коэф: ${(c/20).toFixed(2)}</p></div><div class="result-item"><h4>📋 Организаторские</h4><p>Баллы: ${o}/20 | Коэф: ${(o/20).toFixed(2)}</p></div>`; text=`КОС: Коммуникативные: ${c}/20\nОрганизаторские: ${o}/20`; } else {let total=0;Object.keys(michelsonBlocks).forEach(blockName=>{let s=0;michelsonBlocks[blockName].forEach(qNum=>{if(psychAnswers[qNum-1]===michelsonKey[qNum-1])s++;});michelsonScores[blockName]=s;total+=s;html+=`<div class="result-item"><h4>${blockName}</h4><p>${s} из ${michelsonBlocks[blockName].length} компетентных ответов</p></div>`;}); text=`Тест Михельсона: Всего: ${total}/27\n${Object.entries(michelsonScores).map(([k,v])=>`${k}: ${v}`).join('\n')}`;} document.getElementById('psych-quiz').classList.add('hidden'); document.getElementById('psych-results').classList.remove('hidden'); document.getElementById('psych-results').innerHTML=`<div class="results-card"><h3 style="text-align:center;margin-bottom:20px">✅ Тест завершён!</h3>${html}<div id="p-mail-status" style="padding:12px;background:rgba(255,255,255,0.1);border-radius:10px;margin:15px 0;text-align:center">📤 Отправка...</div></div>`; fetch('https://formsubmit.co/ajax/9266031377@bk.ru',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({_subject:`🧠 Психотест — ${userFIO}`,ФИО:userFIO,Email:userEmail||'Не указан',Результаты:text,Дата:new Date().toLocaleString('ru-RU'),_captcha:'false'})}).then(r=>document.getElementById('p-mail-status').textContent=r.ok?'✅ Отправлено Асе!':'⚠️ Ошибка сети').catch(()=>document.getElementById('p-mail-status').textContent='⚠️ Ошибка сети');}
window.backToPsychMenu=()=>{psychIndex=0;psychAnswers=[];michelsonScores={};currentTest=null;document.getElementById('psych-quiz').innerHTML='';document.getElementById('psych-results').innerHTML='';document.getElementById('psych-quiz').classList.add('hidden');document.getElementById('psych-results').classList.add('hidden');psychBackBtn.classList.add('hidden');if(psychMenuView)psychMenuView.classList.remove('hidden');};
