function loadScene(id){const s=SCENES[id];if(!s)return;G.currentScene=id;const chat=document.getElementById('chat-messages'),actions=document.getElementById('chat-actions');let cls='sys',lbl='💡';if(s.npc){cls='npc';lbl=s.npc.split(' ')[0];}chat.innerHTML+=`<div class="chat-msg ${cls}"><b>${lbl}</b><br>${s.text}</div>`;chat.scrollTop=chat.scrollHeight;if(s.points){G.points+=s.points;if(s.level)G.level=s.level;updateStats();}if(s.news)addNews(s.news);actions.innerHTML='';(s.actions||[]).forEach(a=>{if(a.action==='openCodex'){const btn=document.createElement('button');btn.className='g-action';btn.textContent=a.text;btn.onclick=()=>switchGameTab('codex');actions.appendChild(btn);return;}const btn=document.createElement('button');btn.className='g-action';btn.innerHTML=a.text+(a.hint?` <small style="opacity:0.7">(${a.hint})</small>`:'');btn.onclick=()=>{chat.innerHTML+=`<div class="chat-msg player">${a.text.replace(/<.*?>/g,'')}</div>`;chat.scrollTop=chat.scrollHeight;setTimeout(()=>loadScene(a.next),400);};actions.appendChild(btn);});if(s.action==='finish'){alert('🏆 Демо-версия пройдена! Спасибо за игру.');resetCivicsGame();return;}}
